#!/usr/bin/env bash
# equip.sh — catch-and-release provisioning for one R1 mesh node.
#
# CATCH (plug in over USB) -> EQUIP (this script) -> RELEASE (unplug; it keeps
# running on WiFi and stays in the mesh). Idempotent + verification-heavy: a
# backgrounded `adb shell nohup` can silently fail to replace the station, so we
# confirm the new process via its log + /health before declaring success.
#
# FLASH FIRST: image the device (Android 16 GSI) with the mtkclient toolkit in
# packages/aeon-r1-unknot (the "unknot" flasher; the R1 is a MediaTek MT6765). Then run
# this with --apk: it does the post-flash OS prep itself (launcher, WebView provider,
# lockscreen off, provisioned, audio/camera) PLUS the RELEASE-survival pieces -- a kernel
# wakelock so the CPU doesn't deep-doze and suspend the node on battery, a setsid-detached
# start that survives USB unplug, a boot-rejoin hook, and optional adb-over-wifi. No
# external setup script needed.
#
# Usage:
#   equip.sh -s <serial> -n <node-id> --stages <a..b,c..d> --seed <data-url> [opts]   (self-elect)
#   equip.sh -s <serial> -n <node-id> -r <role> -l <a..b> [opts]                       (pinned)
# Required:
#   -s serial        adb device serial (from `adb devices`)
#   -n node-id       stable id, e.g. r1A
#   and EITHER gossip self-election (preferred, no hardcoded deployments):
#     --stages a..b,c..d  the model's stage plan; the node elects its under-replicated stage
#     --seed DATA-URL     a live node to query for the gossip view, e.g. http://10.0.0.199:8090
#     --target-replicas N replicas/stage to settle toward (default 2)
#   OR a pinned stage:
#     -r role          entry | mid | exit | both
#     -l layers        layer range "a..b" (end-exclusive), e.g. 0..12
# Options:
#   -p peers         seed gossip endpoints "ip:port,ip:port" (use "" for the first node)
#   --knot-url URL   R2 (or any http) knot the node downloads on first boot if none pushed
#   -k knot          on-device knot path (default /data/local/tmp/qwen05-dense.knot)
#   -P data-port     fat-station HTTP port (default 8090)
#   -G gossip-port   UDP gossip port (default 9090)
#   -b binary        host musl fat-station to push (default target/aarch64-unknown-linux-musl/release/fat-station)
#   --tcpip          enable adb-over-wifi (port 5555) so the node is manageable after release
#   --no-start       push + autostart-install only; don't launch now
#   --apk PATH       install the Aeon Shell APK (carries libfatstation.so) + set it as the
#                    home launcher -> in-app reboot-survival node (docs/R1_INAPP_NODE.md)
set -euo pipefail

SERIAL= ROLE= LAYERS= NODEID= PEERS= KNOT=/data/local/tmp/qwen05-dense.knot
DPORT=8090 GPORT=9090 TCPIP=0 NOSTART=0 ADMIT= APK= STAGES= SEED= KNOTURL= TREP=2
BIN="$(cd "$(dirname "$0")/../.." && pwd)/target/aarch64-unknown-linux-musl/release/fat-station"
while [ $# -gt 0 ]; do case "$1" in
  -s) SERIAL=$2; shift 2;; -r) ROLE=$2; shift 2;; -l) LAYERS=$2; shift 2;;
  -n) NODEID=$2; shift 2;; -p) PEERS=$2; shift 2;; -k) KNOT=$2; shift 2;;
  -P) DPORT=$2; shift 2;; -G) GPORT=$2; shift 2;; -b) BIN=$2; shift 2;;
  --tcpip) TCPIP=1; shift;; --no-start) NOSTART=1; shift;;
  --admit) ADMIT="--admit"; shift;;
  --apk) APK=$2; shift 2;;
  --stages) STAGES=$2; shift 2;; --seed) SEED=$2; shift 2;;
  --knot-url) KNOTURL=$2; shift 2;; --target-replicas) TREP=$2; shift 2;;
  *) echo "unknown arg: $1" >&2; exit 2;; esac; done
[ -n "$SERIAL" ] || { echo "missing required arg (-s)" >&2; exit 2; }
# Default node id is "auto" -> the node hashes its hardware id (ANDROID_ID) into a stable,
# privacy-preserving id (raw id never gossiped). Pass -n to pin an explicit id instead.
NODEID=${NODEID:-auto}
# Stage: gossip self-election (--stages, preferred -- no hardcoded deployments) or a pin.
if [ -z "$STAGES" ] && { [ -z "$ROLE" ] || [ -z "$LAYERS" ]; }; then
  echo "need --stages a..b,c..d (gossip self-elect) OR -r ROLE -l LAYERS (pinned)" >&2; exit 2
fi
if [ -n "$STAGES" ]; then
  STAGEARGS="--auto-stage --stages $STAGES ${SEED:+--seed $SEED} --target-replicas $TREP"
  STAGEDESC="auto-stage[$STAGES]"
else
  STAGEARGS="--role $ROLE --layers $LAYERS"
  STAGEDESC="role=$ROLE layers=$LAYERS"
fi
A() { adb -s "$SERIAL" "$@"; }
# R1s vary: some adb shells are root-by-default (uid 0), some are uid 2000 + need
# `su 0 sh -c`. Run privileged commands through asroot so equip works on both.
ROOT_UID=$(A shell 'id -u' 2>/dev/null | tr -d '\r')
asroot() { if [ "$ROOT_UID" = "0" ]; then A shell "$*"; else A shell "su 0 sh -c \"$*\""; fi; }

echo "[equip] $NODEID ($SERIAL): $STAGEDESC port=$DPORT gossip=$GPORT"

# 1) Push the binary (idempotent: skip if same size already there).
[ -f "$BIN" ] || { echo "[equip] binary not found: $BIN (build musl first)" >&2; exit 1; }
LSZ=$(stat -f%z "$BIN" 2>/dev/null || stat -c%s "$BIN")
RSZ=$(A shell 'stat -c%s /data/local/tmp/fat-station 2>/dev/null' | tr -d '\r' || true)
if [ "$LSZ" != "$RSZ" ]; then A push "$BIN" /data/local/tmp/fat-station >/dev/null; A shell 'chmod 755 /data/local/tmp/fat-station'; echo "[equip] pushed fat-station ($LSZ B)"; else echo "[equip] fat-station up to date"; fi
if ! A shell "test -f $KNOT" 2>/dev/null; then
  if [ -n "$KNOTURL" ]; then echo "[equip] knot not on device; node will fetch from R2 on first boot: $KNOTURL"
  else echo "[equip] knot missing on device: $KNOT (push it, or pass --knot-url for R2)" >&2; exit 1; fi
fi

# 2) Detect the node's WiFi IP (data + gossip advertise address).
IP=$(A shell 'ip -o -4 addr show wlan0 2>/dev/null | awk "{print \$4}" | cut -d/ -f1' | tr -d '\r')
[ -n "$IP" ] || { echo "[equip] no wlan0 IP — join WiFi first" >&2; exit 1; }
echo "[equip] wifi ip: $IP"

# 2b) RELEASE-SURVIVAL keep-awake: a released R1 on battery deep-dozes and suspends
#     fat-station. The KERNEL WAKELOCK (root) is the real guarantee — it blocks system
#     suspend entirely, so CPU + WiFi stay fully up. The SCREEN is separate: let the
#     display sleep (saves power and, more importantly, HEAT — a lit panel adds watts
#     and thermal throttle for zero compute). So: short screen timeout, do NOT pin the
#     screen on while charging, and pin WiFi to never-sleep as belt-and-suspenders.
A shell 'settings put global stay_on_while_plugged_in 0; settings put system screen_off_timeout 30000; settings put global wifi_sleep_policy 2' 2>/dev/null || true
asroot "echo fatstation_$NODEID > /sys/power/wake_lock" >/dev/null 2>&1 || true
if asroot "cat /sys/power/wake_lock" 2>/dev/null | tr ' ' '\n' | grep -q "fatstation_$NODEID"; then
  echo "[equip] kernel wakelock held — survives unplug without dozing"
else
  echo "[equip] WARN: wakelock not held; deep-doze may suspend on battery" >&2
fi

# 3) Install boot-autostart hook (reboot survival). Build on the HOST, then push —
#    avoids nested-quote breakage of `adb shell "cat <<EOF…"`. $IP/$4 expand on the
#    device at boot (escaped \$); everything else expands here.
RC="/data/local/tmp/fatstation-boot.sh"
TMPRC=$(mktemp)
cat > "$TMPRC" <<EOF
#!/system/bin/sh
# auto-rejoin the mesh on boot. installed by equip.sh.
until ip -o -4 addr show wlan0 | grep -q inet; do sleep 2; done
su 0 sh -c "echo fatstation_$NODEID > /sys/power/wake_lock" 2>/dev/null
settings put global stay_on_while_plugged_in 0 2>/dev/null
settings put system screen_off_timeout 30000 2>/dev/null
settings put global wifi_sleep_policy 2 2>/dev/null
IP=\$(ip -o -4 addr show wlan0 | awk '{print \$4}' | cut -d/ -f1)
HWID=\$(settings get secure android_id 2>/dev/null)
setsid /data/local/tmp/fat-station --knot $KNOT $STAGEARGS --port $DPORT --gossip-port $GPORT --advertise-host \$IP --node-id $NODEID \${HWID:+--hwid \$HWID} ${PEERS:+--peers $PEERS} $ADMIT > /data/local/tmp/mesh.log 2>&1 &
EOF
A push "$TMPRC" "$RC" >/dev/null && A shell "chmod 755 $RC"
rm -f "$TMPRC"
echo "[equip] boot hook written: $RC (external/within-session path)"

# 3b) IN-APP NODE CONFIG (docs/R1_INAPP_NODE.md) — the proven reboot-survival path. The
#     Aeon Shell launcher reads this on every boot and execs libfatstation.so from its
#     nativeLibraryDir (no su, which this GSI forbids for apps). Written to
#     /data/local/tmp where untrusted_app can read it.
CONF=$(mktemp)
{
  echo "KNOT=$KNOT"
  [ -n "$KNOTURL" ] && echo "KNOT_URL=$KNOTURL"
  echo "PORT=$DPORT"
  echo "GOSSIP_PORT=$GPORT"
  echo "NODE_ID=$NODEID"
  [ -n "$PEERS" ] && echo "PEERS=$PEERS"
  [ -n "$ADMIT" ] && echo "ADMIT=1"
  if [ -n "$STAGES" ]; then
    # Gossip self-election (no hardcoded role/layers): the node picks its under-replicated stage.
    echo "STAGES=$STAGES"
    [ -n "$SEED" ] && echo "SEED=$SEED"
    echo "TARGET_REPLICAS=$TREP"
  else
    echo "ROLE=$ROLE"
    echo "LAYERS=$LAYERS"
  fi
} > "$CONF"
A push "$CONF" /data/local/tmp/mesh-node.conf >/dev/null && A shell 'chmod 644 /data/local/tmp/mesh-node.conf'
rm -f "$CONF"
echo "[equip] in-app node config written: /data/local/tmp/mesh-node.conf"

# 3c) Install the Aeon Shell APK (carries libfatstation.so), do the post-flash OS prep,
#     make it the home launcher, and launch -> the in-app node runs on every boot. Pass
#     --apk PATH to enable. Self-contained: no external setup script needed (the device is
#     flashed with packages/aeon-r1-unknot, then this does the rest).
if [ -n "$APK" ]; then
  [ -f "$APK" ] || { echo "[equip] APK not found: $APK" >&2; exit 1; }
  # Launcher package id. Source rebranded run.aeon.shell -> ai.forkjoin.os
  # (tauri.conf.json identifier); override with APK_PKG=... if it changes again.
  PKG="${APK_PKG:-ai.forkjoin.os}"
  ACT="$PKG/$PKG.MainActivity"
  # install -r only replaces in place when the id AND signature match. A prior
  # build under a DIFFERENT id (e.g. the old run.aeon.shell) stays installed and
  # would keep its own node on :8090 -> port clash. Remove any mismatched prior
  # launcher first (best-effort; no-op when absent).
  for OLD in run.aeon.shell; do
    [ "$OLD" = "$PKG" ] && continue
    A shell "pm list packages 2>/dev/null | grep -q $OLD" >/dev/null 2>&1 \
      && A uninstall "$OLD" >/dev/null 2>&1 \
      && echo "[equip] removed stale launcher $OLD (superseded by $PKG)"
  done
  A install -r "$APK" >/dev/null 2>&1 && echo "[equip] installed APK: $(basename "$APK") ($PKG)"
  A shell "cmd package set-home-activity $ACT" >/dev/null 2>&1 \
    && echo "[equip] Aeon Shell set as home launcher (in-app node runs on boot)"
  # Some R1 BSP builds ship a WebView package but leave the provider unset -> the launcher
  # crashes at WebView init ("No WebView installed"). Select it so the launcher comes up.
  A shell 'cmd webviewupdate set-webview-implementation com.android.webview' >/dev/null 2>&1 \
    && echo "[equip] WebView provider set (com.android.webview)"
  # The stock launcher (com.android.launcher3) CRASHLOOPS on the Android 16 BSP image
  # (AppWidgetManager NPE). Aeon Shell is the home now, so disable the stock one so Android
  # never falls back to it. Harmless on builds where it isn't buggy.
  A shell 'pm disable-user --user 0 com.android.launcher3' >/dev/null 2>&1 \
    && echo "[equip] stock launcher (com.android.launcher3) disabled (crashloops on A16 BSP)"
  # Post-flash OS prep so the launcher comes up clean on boot (no lockscreen / setup wizard)
  # and audio/camera work. GMS appops tolerated (absent on GMS-less BSP builds).
  A shell 'locksettings set-disabled true' 2>/dev/null || true   # the reliable keyguard kill
  A shell 'settings put secure lockscreen.disabled 1; settings put global lockscreen.disabled 1; settings put system lockscreen.disabled 1' 2>/dev/null || true
  A shell 'settings put global device_provisioned 1; settings put secure user_setup_complete 1' 2>/dev/null || true
  # Let the SCREEN sleep (saves power + heat); the kernel wakelock + no-doze keep the
  # NODE serving. Do NOT pin the screen on (svc power stayon) — that just adds heat.
  A shell 'settings put system screen_off_timeout 30000; svc power stayon false; settings put global stay_on_while_plugged_in 0; settings put global wifi_sleep_policy 2' 2>/dev/null || true
  A shell 'dumpsys deviceidle disable' >/dev/null 2>&1 || true   # no doze (released on battery)
  # Match the original A16 prototype's display: override DPI to 120 (the panel stays
  # 480x640, but 320->120 fits ~2.7x more = the "higher resolution" feel) and enable
  # auto-rotate. The stock A16 BSP flash defaults to density 320 + accelerometer_rotation 0.
  A shell "wm density ${R1_DENSITY:-120}; settings put system accelerometer_rotation 1; settings put system user_rotation 0" 2>/dev/null || true
  A shell 'settings put global heads_up_notifications_enabled 0' 2>/dev/null || true
  A shell "pm grant $PKG android.permission.RECORD_AUDIO; pm grant $PKG android.permission.CAMERA" 2>/dev/null || true
  echo "[equip] OS prep: keyguard disabled, provisioned, screen-sleeps + wifi-stays + no-doze (node stays active), display density ${R1_DENSITY:-120} + auto-rotate (prototype parity), audio/camera granted"
  # The in-app launcher owns the node now; don't also start the external one (port clash).
  NOSTART=1
  A shell "am start -n $ACT" >/dev/null 2>&1
  echo "[equip] launched Aeon Shell -> in-app node starting (auto-elects from gossip)"
fi

if [ "$NOSTART" = "0" ]; then
  # 4) Clean restart, fully DETACHED (setsid) so it survives USB unplug.
  #    Root-pkill (procs may be owned by root or shell) + WAIT until the old proc is
  #    actually gone so the new one isn't blocked by the still-held :$DPORT (the
  #    silent stale-station bug). Then start detached.
  asroot "pkill -9 fat-station" 2>/dev/null || true
  for _ in $(seq 1 20); do
    [ -z "$(A shell 'pgrep fat-station' | tr -d '\r')" ] && break; sleep 0.5
  done
  HWID=$(A shell 'settings get secure android_id 2>/dev/null' | tr -d '\r')
  A shell "cd /data/local/tmp && setsid ./fat-station --knot $KNOT $STAGEARGS --port $DPORT --gossip-port $GPORT --advertise-host $IP --node-id $NODEID ${HWID:+--hwid $HWID} ${PEERS:+--peers $PEERS} $ADMIT > mesh.log 2>&1 & sleep 1; echo started pid \$(pgrep fat-station)"
  # 5) VERIFY (silent-fail guard): the NEW station's node-id (not just role) — a stale
  #    leftover would pass a role check but show the wrong node-id.
  sleep 6
  A shell 'grep -iE "gossip|listening|panic|bind" /data/local/tmp/mesh.log | head -3'
  SELF=$(curl -s --max-time 6 "http://$IP:$DPORT/mesh/peers" 2>/dev/null | sed -n 's/.*"self":{"node_id":"\([^"]*\)".*/\1/p')
  # With auto, the running id is the hardware hash (r1-<hex>), not the literal "auto" — just
  # confirm a node came up; with an explicit -n, confirm the exact id (stale-station guard).
  if { [ "$NODEID" = "auto" ] && [ -n "$SELF" ]; } || [ "$SELF" = "$NODEID" ]; then
    echo "[equip] OK: node '$SELF' live at http://$IP:$DPORT"
  else
    echo "[equip] WARN: running node-id='$SELF' != expected '$NODEID' (stale station?) — check mesh.log" >&2
  fi
fi

# 6) Enable adb-over-wifi LAST (it restarts adbd + drops this USB session) so the
#    node is reachable/manageable after RELEASE (unplug) via `adb connect $IP:5555`.
if [ "$TCPIP" = "1" ]; then
  echo "[equip] enabling adb-over-wifi on :5555 (USB adb will drop) ..."
  A tcpip 5555 >/dev/null 2>&1 || true
  echo "[equip] RELEASE-READY: unplug now; reconnect with: adb connect $IP:5555"
fi
echo "[equip] done: $NODEID"
